import pytest


class FakeElement:
    def __init__(self, text="", attrib=None):
        self._text = text
        self.attrib = attrib or {}

    def get_all_text(self, strip=True):
        return self._text.strip() if strip else self._text


class FakeList(list):
    @property
    def first(self):
        return self[0] if self else None


class FakePage:
    """Minimal stand-in for scrapling's Adaptor, keyed by exact CSS selector."""

    def __init__(self, css_map: dict[str, list[FakeElement]], url="https://example.com/a"):
        self._css_map = css_map
        self.url = url
        self.html_content = ""

    def css(self, selector):
        return FakeList(self._css_map.get(selector, []))


@pytest.fixture
def fake_page_factory():
    return FakePage
