from unittest.mock import patch, MagicMock
import gzip

import pytest

from base import _fetch_xml, discover_sitemap_urls, parse_french_date, parse_numeric_date


class TestFetchXml:
    @patch("base.urllib.request.urlopen")
    def test_plain_xml(self, mock_urlopen):
        mock_urlopen.return_value.__enter__.return_value.read.return_value = b"<a/>"
        assert _fetch_xml("http://x") == "<a/>"

    @patch("base.urllib.request.urlopen")
    def test_gzip_response_is_decompressed(self, mock_urlopen):
        payload = gzip.compress(b"<a/>")
        mock_urlopen.return_value.__enter__.return_value.read.return_value = payload
        assert _fetch_xml("http://x") == "<a/>"

    @patch("base.urllib.request.urlopen")
    def test_strips_leading_whitespace(self, mock_urlopen):
        mock_urlopen.return_value.__enter__.return_value.read.return_value = b"\n\n<a/>"
        assert _fetch_xml("http://x") == "<a/>"

    @patch("base.urllib.request.urlopen", side_effect=TimeoutError)
    def test_timeout_propagates(self, mock_urlopen):
        with pytest.raises(TimeoutError):
            _fetch_xml("http://x")


class TestDiscoverSitemapUrls:
    @patch("base._fetch_xml")
    def test_flat_urlset_yields_locs(self, mock_fetch):
        mock_fetch.return_value = (
            "<urlset><url><loc>https://x/a</loc></url>"
            "<url><loc>https://x/b</loc></url></urlset>"
        )
        assert list(discover_sitemap_urls("http://sm")) == ["https://x/a", "https://x/b"]

    @patch("base._fetch_xml")
    def test_sitemapindex_recurses(self, mock_fetch):
        index = "<sitemapindex><sitemap><loc>http://sm/2</loc></sitemap></sitemapindex>"
        leaf = "<urlset><url><loc>https://x/a</loc></url></urlset>"
        mock_fetch.side_effect = [index, leaf]
        assert list(discover_sitemap_urls("http://sm/1")) == ["https://x/a"]

    @patch("base._fetch_xml")
    def test_nested_image_loc_not_picked_up(self, mock_fetch):
        mock_fetch.return_value = (
            "<urlset xmlns:image='http://x'>"
            "<url><loc>https://x/a</loc>"
            "<image:image><image:loc>https://x/img.jpg</image:loc></image:image>"
            "</url></urlset>"
        )
        assert list(discover_sitemap_urls("http://sm")) == ["https://x/a"]


class TestParseFrenchDate:
    @pytest.mark.parametrize("text,expected", [
        ("22 juin 2019", "2019-06-22"),
        ("octobre 30, 2017", "2017-10-30"),
        ("22 Février 2020", "2020-02-22"),
        ("22 fevrier 2020", "2020-02-22"),
    ])
    def test_valid_formats(self, text, expected):
        assert parse_french_date(text) == expected

    def test_unknown_month_returns_none(self):
        assert parse_french_date("22 notamonth 2019") is None

    def test_no_match_returns_none(self):
        assert parse_french_date("no date here") is None

    def test_out_of_range_day_raises(self):
        # documents current (arguably buggy) behavior — no range validation
        with pytest.raises(ValueError):
            parse_french_date("32 janvier 2019")


class TestParseNumericDate:
    def test_basic(self):
        assert parse_numeric_date("13/07/2026") == "2026-07-13"

    def test_with_trailing_time(self):
        assert parse_numeric_date("13/07/2026 14:30") == "2026-07-13"

    def test_no_match_returns_none(self):
        assert parse_numeric_date("not a date") is None

    def test_invalid_month_raises(self):
        with pytest.raises(ValueError):
            parse_numeric_date("13/13/2026")
