from unittest.mock import patch

from base import NewsSource
from models import SiteSelectors
from tests.conftest import FakeElement, FakePage


class DummySource(NewsSource):
    source_name = "dummy"
    selectors = SiteSelectors(
        title="h1", body="p", author=".author",
        published_date=".date", published_date_attr="datetime",
        category=".cat",
    )


def make_source_with_page(css_map):
    src = DummySource()
    page = FakePage(css_map)
    src.fetch = lambda url: page  # bypass real network
    return src


def test_missing_title_returns_none():
    src = make_source_with_page({"h1": []})
    assert src.parse_article("https://x/a") is None


def test_body_excludes_blank_paragraphs():
    src = make_source_with_page({
        "h1": [FakeElement("Title")],
        "p": [FakeElement("first"), FakeElement("   "), FakeElement("second")],
    })
    article = src.parse_article("https://x/a")
    assert article.body == "first\n\nsecond"


def test_author_absent_when_selector_unset():
    src = DummySource()
    src.selectors = SiteSelectors(title="h1", body="p", author=None)
    src.fetch = lambda url: FakePage({"h1": [FakeElement("T")], "p": []})
    article = src.parse_article("https://x/a")
    assert article.author is None


def test_published_date_from_attr():
    src = make_source_with_page({
        "h1": [FakeElement("T")], "p": [],
        ".date": [FakeElement(attrib={"datetime": "2026-07-13"})],
    })
    assert src.parse_article("https://x/a").published_date == "2026-07-13"


def test_embed_url_skips_about_blank_iframe():
    src = make_source_with_page({
        "h1": [FakeElement("T")], "p": [],
        "iframe": [
            FakeElement(attrib={"src": "about:blank"}),
            FakeElement(attrib={"src": "https://yt/embed/1"}),
        ],
    })
    assert src.parse_article("https://x/a").embed_url == "https://yt/embed/1"


def test_embed_url_falls_back_to_video_source():
    src = make_source_with_page({
        "h1": [FakeElement("T")], "p": [], "iframe": [],
        "video source": [FakeElement(attrib={"src": "https://x/v.mp4"})],
    })
    assert src.parse_article("https://x/a").embed_url == "https://x/v.mp4"


def test_extract_images_prefers_data_src_and_dedupes():
    src = make_source_with_page({
        "h1": [FakeElement("T")], "p": [],
        DummySource._IMG_CONTAINERS: [
            FakeElement(attrib={"data-src": "/img1.jpg", "src": "/placeholder.gif"}),
            FakeElement(attrib={"src": "data:image/png;base64,xx"}),  # skipped
            FakeElement(attrib={"src": "/img1.jpg"}),  # dup after resolve
        ],
    })
    article = src.parse_article("https://x/a")
    assert article.images == ["https://x/img1.jpg"]
