import pytest

from providers import MadagascarTribune, FreeNews, Moov, PROVIDERS
from base import NewsSource


class TestIsArticleLink:
    @pytest.mark.parametrize("href,expected", [
        (None, False),
        ("article-slug.html", True),
        ("category-.html", False),          # rubrique convention
        ("https://external.com/a.html", False),
        ("/absolute/path.html", False),
        ("_Author,123_.html", False),
        ("article-slug", False),            # no .html
    ])
    def test_cases(self, href, expected):
        assert MadagascarTribune._is_article_link(href) is expected


class TestDiscoverCategories:
    @patch("providers.Fetcher.get")
    def test_dedupes_and_sorts_numerically(self, mock_get):
        mock_get.return_value = MagicMock(
            html_content="rubrique2 rubrique10 rubrique2"
        )
        src = MadagascarTribune()
        cats = src._discover_categories()
        assert cats[-2:] == [
            "https://madagascar-tribune.com/spip.php?rubrique2",
            "https://madagascar-tribune.com/spip.php?rubrique10",
        ]

    @patch("providers.Fetcher.get", side_effect=RuntimeError)
    def test_homepage_fetch_failure_returns_empty(self, mock_get):
        assert MadagascarTribune()._discover_categories() == []


class TestFreeNewsListArticleUrls:
    @patch("providers.urllib.request.urlopen")
    def test_stops_on_400(self, mock_urlopen):
        mock_urlopen.side_effect = urllib.error.HTTPError(
            "url", 400, "bad page", {}, None
        )
        assert list(FreeNews().list_article_urls()) == []

    @patch("providers.urllib.request.urlopen")
    def test_other_http_errors_propagate(self, mock_urlopen):
        mock_urlopen.side_effect = urllib.error.HTTPError(
            "url", 500, "server error", {}, None
        )
        with pytest.raises(urllib.error.HTTPError):
            list(FreeNews().list_article_urls())

    @patch("providers.urllib.request.urlopen")
    def test_paginates_until_empty(self, mock_urlopen):
        import json as _json
        page1 = MagicMock()
        page1.__enter__.return_value.read.return_value = _json.dumps(
            [{"link": "https://x/a"}]
        ).encode()
        page2 = MagicMock()
        page2.__enter__.return_value.read.return_value = b"[]"
        mock_urlopen.side_effect = [page1, page2]
        assert list(FreeNews().list_article_urls()) == ["https://x/a"]


class TestMoovListArticleUrls:
    @patch("providers.Fetcher.get")
    def test_dedupes_and_skips_non_article_links(self, mock_get):
        home = MagicMock()
        home.css.return_value = []  # simplify: no outbound links from seed
        mock_get.return_value = home
        urls = list(Moov().list_article_urls())
        assert urls == []

    # TODO: build a FakePage-based fixture to simulate a 2-hop link graph
    # and assert BFS order + no revisits.


def test_providers_registry_has_unique_source_names_and_valid_types():
    names = [cls.source_name for cls in PROVIDERS.values()]
    assert len(names) == len(set(names))
    for key, cls in PROVIDERS.items():
        assert issubclass(cls, NewsSource)
        assert cls.source_name == key
